    public interface SessionStore {
        void put(AuthenticatedSession session);
        Optional<AuthenticatedSession> get(String sessionId);
        void revoke(String sessionId);
    }

    public static final class InMemorySessionStore implements SessionStore {
        private final ConcurrentHashMap<String, AuthenticatedSession> sessions = new ConcurrentHashMap<>();

        @Override
        public void put(AuthenticatedSession session) {
            sessions.put(session.sessionId, session);
        }

        @Override
        public Optional<AuthenticatedSession> get(String sessionId) {
            AuthenticatedSession s = sessions.get(sessionId);
            if (s == null) return Optional.empty();
            if (Instant.now().isAfter(s.expiresAt)) {
                sessions.remove(sessionId);
                return Optional.empty();
            }
            return Optional.of(s);
        }

        @Override
        public void revoke(String sessionId) {
            sessions.remove(sessionId);
        }
    }

